module RefModule (clk, reset, load, data_in, data_out);
   input clk, reset, load;
   input [3:0] data_in;
   output data_out;

   reg [3:0] unused_shift_reg;
   reg data_out;

always @(posedge clk or posedge reset) begin
    if (reset) 
    begin
        unused_shift_reg <= 4'b0000;
        data_out <= 0;
    end 
    else 
    begin
        if (load) 
            unused_shift_reg <= data_in;
        else 
        begin
            data_out <= unused_shift_reg[3];
            unused_shift_reg <= {unused_shift_reg[2:0], 1'b0};
        end
    end
end

endmodule
